# 创建备份目录，以日期命名
$backupDate = Get-Date -Format "yyyyMMdd"
$backupDir = "C:\Users\WH\.openclaw\backup-$backupDate"
New-Item -ItemType Directory -Path $backupDir -Force

# 复制整个.openclaw目录内容（排除.git目录）
Get-ChildItem "C:\Users\WH\.openclaw" -Exclude ".git", "backup-*" | ForEach-Object {
    if ($_.PSIsContainer) {
        Copy-Item $_.FullName "$backupDir\$($_.Name)" -Recurse -Force
    } else {
        Copy-Item $_.FullName "$backupDir\$($_.Name)" -Force
    }
}

Write-Output "备份创建完成：$backupDir"
Write-Output "备份大小：" 
(Get-ChildItem $backupDir -Recurse | Measure-Object Length -Sum).Sum / 1KB | ForEach-Object { "$([math]::Round($_, 2)) KB" }
